import{o as n,c as s,d as a}from"./app.5e36e714.js";const p='{"title":"关键字","description":"","frontmatter":{"title":"关键字"},"headers":[{"level":2,"title":"defer","slug":"defer"},{"level":2,"title":"panic 和 recover","slug":"panic-和-recover"},{"level":2,"title":"make 和 new","slug":"make-和-new"}],"relativePath":"docs/golang/base/keyword.md","lastUpdated":1655448561246}',t={},o=a('<h2 id="defer"><a class="header-anchor" href="#defer" aria-hidden="true">#</a> defer</h2><ol><li><p>go执行到一个defer时，不会立即执行defer后的语句，而是将defer后的语句压入到一个栈中，然后继续执行函数下面的语句。<strong>defer将语句放入栈时，也会将相关的值拷贝入栈</strong></p></li><li><p>函数执行完毕后，再从defer栈中依次取出语句执行（遵循栈先入后出的规则 FILO）</p></li></ol><div class="language-go"><pre><code><span class="token keyword">package</span> main\n\n<span class="token keyword">import</span> <span class="token string">&quot;fmt&quot;</span>\n\n<span class="token keyword">func</span> <span class="token function">sum</span><span class="token punctuation">(</span>n1 <span class="token builtin">int</span><span class="token punctuation">,</span> n2 <span class="token builtin">int</span><span class="token punctuation">)</span> <span class="token builtin">int</span> <span class="token punctuation">{</span>\n  <span class="token keyword">defer</span> fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;n1 =&quot;</span><span class="token punctuation">,</span> n1<span class="token punctuation">)</span>\n  <span class="token keyword">defer</span> fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;n2 =&quot;</span><span class="token punctuation">,</span> n2<span class="token punctuation">)</span>\n  n1<span class="token operator">++</span>\n  n2<span class="token operator">++</span>\n  res <span class="token operator">:=</span> n1 <span class="token operator">+</span> n2\n  fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;res =&quot;</span><span class="token punctuation">,</span> res<span class="token punctuation">)</span>\n  <span class="token keyword">return</span> res\n<span class="token punctuation">}</span>\n\n<span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span>  <span class="token punctuation">{</span>\n  res <span class="token operator">:=</span> <span class="token function">sum</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">,</span><span class="token number">20</span><span class="token punctuation">)</span>\n  fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;main res =&quot;</span><span class="token punctuation">,</span> res<span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n</code></pre></div><ol start="3"><li>defer、return、返回值三者的执行逻辑应该是：return最先执行，return负责将结果写入返回值中；接着defer开始执行一些收尾工作；最后函数携带当前返回值退出。如果函数的返回值是无名的（不带命名返回值），则go语言会在执行return的时候会执行一个类似创建一个临时变量作为保存return值的动作，而有名返回值的函数，由于返回值在函数定义的时候已经将该变量进行定义，在执行return的时候会先执行返回值保存操作，而后续的defer函数会改变这个返回值(虽然defer是在return之后执行的，但是由于使用的函数定义的变量，所以执行defer操作后对该变量的修改会影响到return的值。</li></ol><div class="language-go"><pre><code><span class="token keyword">package</span> main\n\n<span class="token keyword">import</span> <span class="token punctuation">(</span>\n    <span class="token string">&quot;fmt&quot;</span>\n<span class="token punctuation">)</span>\n\n<span class="token keyword">func</span> <span class="token function">test</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token builtin">int</span> <span class="token punctuation">{</span>\n    a <span class="token operator">:=</span> <span class="token number">1</span>\n    <span class="token keyword">defer</span> <span class="token keyword">func</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n        a <span class="token operator">=</span> <span class="token number">4</span>\n    <span class="token punctuation">}</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n    <span class="token keyword">return</span> a\n<span class="token punctuation">}</span>\n\n<span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    a <span class="token operator">:=</span> <span class="token function">test</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n    fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;a&quot;</span><span class="token punctuation">,</span> a<span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n\na <span class="token number">1</span>\n</code></pre></div><div class="language-go"><pre><code><span class="token keyword">package</span> main\n\n<span class="token keyword">import</span> <span class="token punctuation">(</span>\n    <span class="token string">&quot;fmt&quot;</span>\n<span class="token punctuation">)</span>\n\n<span class="token keyword">func</span> <span class="token function">test</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">(</span>a <span class="token builtin">int</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    a <span class="token operator">=</span> <span class="token number">1</span>\n    <span class="token keyword">defer</span> <span class="token keyword">func</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n        a <span class="token operator">=</span> <span class="token number">4</span>\n    <span class="token punctuation">}</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n    <span class="token keyword">return</span>\n<span class="token punctuation">}</span>\n\n<span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    a <span class="token operator">:=</span> <span class="token function">test</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n    fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;a&quot;</span><span class="token punctuation">,</span> a<span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n\na <span class="token number">4</span>\n</code></pre></div><ol start="4"><li>defer最主要的价值是在当函数执行完毕后，可以及时释放函数创建的资源</li></ol><div class="language-go"><pre><code><span class="token keyword">func</span> <span class="token function">test</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  connect <span class="token operator">=</span> <span class="token function">openDatabase</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n  <span class="token keyword">defer</span> connect<span class="token punctuation">.</span><span class="token function">close</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n    <span class="token comment">// 其它代码</span>\n<span class="token punctuation">}</span>\n</code></pre></div><h2 id="panic-和-recover"><a class="header-anchor" href="#panic-和-recover" aria-hidden="true">#</a> panic 和 recover</h2><p><code>panic</code> 能够改变程序的控制流，调用 <code>panic</code> 后会立刻停止执行当前函数的剩余代码，并在当前 Goroutine 中递归执行调用方的 <code>defer</code></p><p><code>recover</code> 可以中止 <code>panic</code> 造成的程序崩溃。它是一个只能在 <code>defer</code> 中发挥作用的函数，在其他作用域中调用不会发挥作用</p><div class="language-go"><pre><code><span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  <span class="token keyword">defer</span> fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;in main&quot;</span><span class="token punctuation">)</span>\n\n  <span class="token keyword">defer</span> <span class="token keyword">func</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span>\n    <span class="token keyword">if</span> err <span class="token operator">:=</span> <span class="token function">recover</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span>\n      fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span>\n    <span class="token punctuation">}</span>\n  <span class="token punctuation">}</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n\n  <span class="token function">panic</span><span class="token punctuation">(</span><span class="token string">&quot;unknown err&quot;</span><span class="token punctuation">)</span>\n\n  fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;end&quot;</span><span class="token punctuation">)</span> <span class="token comment">// 这里代码不会执行了</span>\n<span class="token punctuation">}</span>\n\n$ <span class="token keyword">go</span> run main<span class="token punctuation">.</span><span class="token keyword">go</span>\nunknown err\nin main\n</code></pre></div><p><code>panic</code> 只会触发当前 Goroutine 的 <code>defer</code></p><div class="language-go"><pre><code><span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  <span class="token keyword">defer</span> <span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;in main&quot;</span><span class="token punctuation">)</span>\n  <span class="token keyword">go</span> <span class="token keyword">func</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    <span class="token keyword">defer</span> <span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;in goroutine&quot;</span><span class="token punctuation">)</span>\n    <span class="token function">panic</span><span class="token punctuation">(</span><span class="token string">&quot;&quot;</span><span class="token punctuation">)</span>\n  <span class="token punctuation">}</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n\n  time<span class="token punctuation">.</span><span class="token function">Sleep</span><span class="token punctuation">(</span><span class="token number">1</span> <span class="token operator">*</span> time<span class="token punctuation">.</span>Second<span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n\n$ <span class="token keyword">go</span> run main<span class="token punctuation">.</span><span class="token keyword">go</span>\nin goroutine\n<span class="token builtin">panic</span><span class="token punctuation">:</span>\n<span class="token operator">...</span>\n</code></pre></div><p><code>recover</code> 只有在 <code>defer</code> 中调用才会生效</p><div class="language-go"><pre><code><span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  <span class="token keyword">defer</span> fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;in main&quot;</span><span class="token punctuation">)</span>\n  <span class="token keyword">if</span> err <span class="token operator">:=</span> <span class="token function">recover</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span>\n    fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span>\n  <span class="token punctuation">}</span>\n\n  <span class="token function">panic</span><span class="token punctuation">(</span><span class="token string">&quot;unknown err&quot;</span><span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n\n$ <span class="token keyword">go</span> run main<span class="token punctuation">.</span><span class="token keyword">go</span>\nin main\n<span class="token builtin">panic</span><span class="token punctuation">:</span> unknown err\n\ngoroutine <span class="token number">1</span> <span class="token punctuation">[</span>running<span class="token punctuation">]</span><span class="token punctuation">:</span>\nmain<span class="token punctuation">.</span><span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n  <span class="token operator">...</span>\nexit status <span class="token number">2</span>\n</code></pre></div><p><code>panic</code> 允许在 <code>defer</code> 中嵌套多次调用</p><div class="language-go"><pre><code><span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  <span class="token keyword">defer</span> fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;in main&quot;</span><span class="token punctuation">)</span>\n  <span class="token keyword">defer</span> <span class="token keyword">func</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    <span class="token keyword">defer</span> <span class="token keyword">func</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n      <span class="token function">panic</span><span class="token punctuation">(</span><span class="token string">&quot;panic again and again&quot;</span><span class="token punctuation">)</span>\n    <span class="token punctuation">}</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n    <span class="token function">panic</span><span class="token punctuation">(</span><span class="token string">&quot;panic again&quot;</span><span class="token punctuation">)</span>\n  <span class="token punctuation">}</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n\n  <span class="token function">panic</span><span class="token punctuation">(</span><span class="token string">&quot;panic once&quot;</span><span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n\n$ <span class="token keyword">go</span> run main<span class="token punctuation">.</span><span class="token keyword">go</span>\nin main\n<span class="token builtin">panic</span><span class="token punctuation">:</span> <span class="token builtin">panic</span> once\n  <span class="token builtin">panic</span><span class="token punctuation">:</span> <span class="token builtin">panic</span> again\n  <span class="token builtin">panic</span><span class="token punctuation">:</span> <span class="token builtin">panic</span> again and again\n\ngoroutine <span class="token number">1</span> <span class="token punctuation">[</span>running<span class="token punctuation">]</span><span class="token punctuation">:</span>\n<span class="token operator">...</span>\nexit status <span class="token number">2</span>\n</code></pre></div><h2 id="make-和-new"><a class="header-anchor" href="#make-和-new" aria-hidden="true">#</a> make 和 new</h2><p><code>make</code> 的作用是初始化内置的数据结构，也就是我们在前面提到的切片、哈希表和 Channel</p><div class="language-go"><pre><code>slice <span class="token operator">:=</span> <span class="token function">make</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token builtin">int</span><span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">,</span> <span class="token number">100</span><span class="token punctuation">)</span>\nhash <span class="token operator">:=</span> <span class="token function">make</span><span class="token punctuation">(</span><span class="token keyword">map</span><span class="token punctuation">[</span><span class="token builtin">int</span><span class="token punctuation">]</span><span class="token builtin">bool</span><span class="token punctuation">,</span> <span class="token number">10</span><span class="token punctuation">)</span>\nch <span class="token operator">:=</span> <span class="token function">make</span><span class="token punctuation">(</span><span class="token keyword">chan</span> <span class="token builtin">int</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">)</span>\n</code></pre></div><p><code>new</code> 的作用是根据传入的类型分配一片内存空间并返回指向这片内存空间的指针</p><div class="language-go"><pre><code>i <span class="token operator">:=</span> <span class="token function">new</span><span class="token punctuation">(</span><span class="token builtin">int</span><span class="token punctuation">)</span>\n\n<span class="token keyword">var</span> v <span class="token builtin">int</span>\ni <span class="token operator">:=</span> <span class="token operator">&amp;</span>v\n</code></pre></div>',23);t.render=function(a,p,t,c,e,u){return n(),s("div",null,[o])};export default t;export{p as __pageData};
